### 3.3 EF Core Entity Configurations

#### 3.3.1 TradeEntityConfiguration
**Dosya:** `src/Traxon.CryptoTrader.Infrastructure/Persistence/Configurations/TradeEntityConfiguration.cs`

```csharp
using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.Metadata.Builders;
using Traxon.CryptoTrader.Domain.Trading;

namespace Traxon.CryptoTrader.Infrastructure.Persistence.Configurations;

public sealed class TradeEntityConfiguration : IEntityTypeConfiguration<Trade>
{
    public void Configure(EntityTypeBuilder<Trade> builder)
    {
        builder.ToTable("Trades");
        builder.HasKey(t => t.Id);

        builder.Property(t => t.Id)
            .ValueGeneratedNever();  // Guid, domain tarafından üretilir

        builder.Property(t => t.Engine)
            .HasMaxLength(20)
            .IsRequired();

        // Asset value object — owned entity olarak string Symbol sütununa map
        builder.OwnsOne(t => t.Asset, a =>
        {
            a.Property(x => x.Symbol)
                .HasColumnName("Symbol")
                .HasMaxLength(20)
                .IsRequired();
        });

        // TimeFrame value object
        builder.OwnsOne(t => t.TimeFrame, tf =>
        {
            tf.Property(x => x.Value)
                .HasColumnName("TimeFrame")
                .HasMaxLength(5)
                .IsRequired();
        });

        builder.Property(t => t.Direction)
            .HasConversion<string>()
            .HasMaxLength(10)
            .IsRequired();

        builder.Property(t => t.EntryPrice)
            .HasColumnType("decimal(18,8)")
            .IsRequired();

        builder.Property(t => t.ExitPrice)
            .HasColumnType("decimal(18,8)");

        builder.Property(t => t.FairValue)
            .HasColumnType("decimal(18,8)")
            .IsRequired();

        builder.Property(t => t.Edge)
            .HasColumnType("decimal(18,8)")
            .IsRequired();

        builder.Property(t => t.PositionSize)
            .HasColumnType("decimal(18,4)")
            .IsRequired();

        builder.Property(t => t.KellyFraction)
            .HasColumnType("decimal(18,8)")
            .IsRequired();

        builder.Property(t => t.MuEstimate)
            .HasColumnType("decimal(18,12)")
            .IsRequired();

        builder.Property(t => t.SigmaEstimate)
            .HasColumnType("decimal(18,12)")
            .IsRequired();

        builder.Property(t => t.Regime)
            .HasConversion<string>()
            .HasMaxLength(20)
            .IsRequired();

        builder.Property(t => t.IndicatorSnapshot)
            .HasColumnType("nvarchar(max)")
            .IsRequired();

        builder.Property(t => t.EntryReason)
            .HasMaxLength(500)
            .IsRequired();

        builder.Property(t => t.OpenedAt)
            .HasColumnType("datetime2")
            .IsRequired();

        builder.Property(t => t.ClosedAt)
            .HasColumnType("datetime2");

        builder.Property(t => t.Status)
            .HasConversion<string>()
            .HasMaxLength(10)
            .IsRequired();

        builder.Property(t => t.Outcome)
            .HasConversion<string>()
            .HasMaxLength(10);

        builder.Property(t => t.PnL)
            .HasColumnType("decimal(18,4)");

        builder.HasIndex(t => new { t.Engine, t.OpenedAt })
            .HasDatabaseName("IX_Trades_Engine_OpenedAt");

        // Asset.Symbol için ek index (Engine+Symbol filtresi için)
        // Shadow property olarak
        builder.HasIndex("Engine", "Asset_Symbol", "OpenedAt")
            .HasDatabaseName("IX_Trades_Engine_Symbol_OpenedAt");
    }
}
```

**NOT:** `Trade.Asset` owned entity olarak EF Core'da `OwnsOne` ile map edilir. Asset value object'in `Symbol` property'si EF Core için `HasColumnName("Symbol")` ile `Trade` tablosuna gömülür.

#### 3.3.2 CandleEntityConfiguration
**Dosya:** `src/Traxon.CryptoTrader.Infrastructure/Persistence/Configurations/CandleEntityConfiguration.cs`

```csharp
using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.Metadata.Builders;
using Traxon.CryptoTrader.Domain.Market;

namespace Traxon.CryptoTrader.Infrastructure.Persistence.Configurations;

public sealed class CandleEntityConfiguration : IEntityTypeConfiguration<Candle>
{
    public void Configure(EntityTypeBuilder<Candle> builder)
    {
        builder.ToTable("Candles");
        builder.HasKey(c => c.Id);

        builder.Property(c => c.Id)
            .UseIdentityColumn();

        builder.OwnsOne(c => c.Asset, a =>
        {
            a.Property(x => x.Symbol)
                .HasColumnName("Symbol")
                .HasMaxLength(20)
                .IsRequired();
        });

        builder.OwnsOne(c => c.TimeFrame, tf =>
        {
            tf.Property(x => x.Value)
                .HasColumnName("Interval")
                .HasMaxLength(5)
                .IsRequired();
        });

        builder.Property(c => c.OpenTime)
            .HasColumnType("datetime2")
            .IsRequired();

        builder.Property(c => c.CloseTime)
            .HasColumnType("datetime2")
            .IsRequired();

        builder.Property(c => c.Open)
            .HasColumnType("decimal(18,8)")
            .IsRequired();

        builder.Property(c => c.High)
            .HasColumnType("decimal(18,8)")
            .IsRequired();

        builder.Property(c => c.Low)
            .HasColumnType("decimal(18,8)")
            .IsRequired();

        builder.Property(c => c.Close)
            .HasColumnType("decimal(18,8)")
            .IsRequired();

        builder.Property(c => c.Volume)
            .HasColumnType("decimal(18,8)")
            .IsRequired();

        builder.Property(c => c.QuoteVolume)
            .HasColumnType("decimal(18,8)")
            .IsRequired();

        builder.Property(c => c.TradeCount)
            .IsRequired();

        builder.Property(c => c.IsClosed)
            .IsRequired();

        // Candle.Id, Binance OpenTime Unix ms timestamp'ı.
        // Symbol+Interval+OpenTime unique constraint:
        builder.HasIndex("Symbol", "Interval", "OpenTime")
            .HasDatabaseName("IX_Candles_Symbol_Interval_OpenTime")
            .IsUnique();
    }
}
```

**ÖNEMLİ NOT:** `Candle.Id` zaten `long` ve Binance'den gelen OpenTime (Unix ms) olduğu için `ValueGeneratedNever()` kullan — `UseIdentityColumn()` DEĞİL. Bu, `CandleEntityConfiguration`'da şöyle olmalı:
```csharp
builder.Property(c => c.Id)
    .ValueGeneratedNever();
```

